#!/usr/bin/env node
// scripts/apply-supabase.mjs
// Reads the SQL generated by scripts/4-init-waitlists.sh and applies
// concert_object_id + waitlist_object_id updates to Supabase automatically.
// Run: node scripts/apply-supabase.mjs
import { createClient } from '@supabase/supabase-js'
import { readFileSync, existsSync } from 'fs'
import { fileURLToPath } from 'url'
import { dirname, join } from 'path'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = join(__dirname, '..')

// Load .env.local
const envPath = join(ROOT, '.env.local')
if (!existsSync(envPath)) {
  console.error('❌  .env.local not found at', envPath)
  process.exit(1)
}
const envRaw = readFileSync(envPath, 'utf8')
const env = Object.fromEntries(
  envRaw.split('\n')
    .filter(l => l.includes('=') && !l.startsWith('#'))
    .map(l => { const i = l.indexOf('='); return [l.slice(0, i).trim(), l.slice(i + 1).trim()] })
)

const SUPABASE_URL = env['VITE_SUPABASE_URL']
const SUPABASE_KEY = env['VITE_SUPABASE_ANON_KEY']

if (!SUPABASE_URL || !SUPABASE_KEY) {
  console.error('❌  Could not find VITE_SUPABASE_URL or VITE_SUPABASE_ANON_KEY in .env.local')
  process.exit(1)
}

// Parse supabase-update.sql generated by 4-init-waitlists.sh
const sqlPath = join(__dirname, 'supabase-update.sql')
if (!existsSync(sqlPath)) {
  console.error('❌  supabase-update.sql not found.')
  console.error('    Run scripts/4-init-waitlists.sh first.')
  process.exit(1)
}

const sql = readFileSync(sqlPath, 'utf8')

/**
 * Parse each UPDATE block from the generated SQL:
 *   UPDATE concerts
 *   SET concert_object_id = '0x...', waitlist_object_id = '0x...', ...
 *   WHERE id = '1';  -- Event Name
 */
const updates = []
const blockRegex = /UPDATE concerts\s+SET\s+([\s\S]*?)\s+WHERE\s+id\s*=\s*'(\d+)'/g
let m
while ((m = blockRegex.exec(sql)) !== null) {
  const setClause = m[1]
  const id = m[2]

  const extract = (key) => {
    // handles:  key = 'value'  or  "key" = value  or  key = number
    const re = new RegExp(`["\\[]?${key}["\\]]?\\s*=\\s*'?([^',;\\n]+)'?`)
    const match = setClause.match(re)
    return match ? match[1].trim().replace(/^'|'$/g, '') : null
  }

  updates.push({
    id,
    concert_object_id: extract('concert_object_id'),
    waitlist_object_id: extract('waitlist_object_id'),
    artist: extract('artist'),
    availableTickets: extract('"availableTickets"') ?? extract('availableTickets'),
    price: extract('price'),
  })
}

if (updates.length === 0) {
  console.error('❌  No UPDATE statements found in supabase-update.sql.')
  console.error('    Re-run scripts/4-init-waitlists.sh to regenerate.')
  process.exit(1)
}

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY)

console.log('\n🎫  TiX-One Supabase Sync')
console.log('════════════════════════════════════════')
console.log(`📡  URL : ${SUPABASE_URL}`)
console.log(`📋  SQL : ${sqlPath}`)
console.log(`🔄  ${updates.length} concert updates to apply...\n`)

let successCount = 0
let failCount = 0

for (const row of updates) {
  const payload = {}
  if (row.concert_object_id)  payload.concert_object_id  = row.concert_object_id
  if (row.waitlist_object_id) payload.waitlist_object_id = row.waitlist_object_id
  if (row.artist)             payload.artist             = row.artist
  if (row.availableTickets)   payload.availableTickets   = Number(row.availableTickets)
  if (row.price)              payload.price              = row.price

  const { error } = await supabase.from('concerts').update(payload).eq('id', row.id)

  if (error) {
    console.log(`  [${row.id}] ❌  ${error.message}`)
    failCount++
  } else {
    console.log(`  [${row.id}] ✅  waitlist=${row.waitlist_object_id?.slice(0, 12)}…`)
    successCount++
  }
}

console.log('\n' + '═'.repeat(42))
if (failCount === 0) {
  console.log(`🎉  All ${successCount} concerts synced to Supabase!`)
} else {
  console.log(`⚠️  ${successCount} succeeded, ${failCount} failed.`)
  if (failCount === updates.length) {
    console.log('\n  If you see "waitlist_object_id column not found", run this in')
    console.log('  Supabase → SQL Editor first:')
    console.log('\n  ALTER TABLE concerts ADD COLUMN waitlist_object_id TEXT;\n')
    console.log('  Then re-run: node scripts/apply-supabase.mjs')
  }
}
console.log('')

